const response = $input.first().json;
const user_id = response.UserID || response.user_id || response.id || response.data?.user_id || response.data?.id || '';
if (!user_id) throw new Error('No user_id for chatto.gpt');
return [{ json: { username: 'chatto.gpt', threat: 'HIGH', user_id: String(user_id) } }];

const uid_data = $('Extract UID A').item.json;
const username = uid_data.username;
const threat = uid_data.threat;
const data = $input.first().json;
const rawItems = data?.data?.items || data?.collector || [];
const items = rawItems.map(i => i.media || i);
const reels = items
  .filter(item => item.media_type === 2 || item.is_video === true)
  .sort((a, b) => (b.play_count || b.view_count || 0) - (a.play_count || a.view_count || 0))
  .slice(0, 10)
  .map(item => ({
    username,
    threat,
    reel_url: 'https://www.instagram.com/reel/' + (item.code || item.shortcode) + '/',
    video_url: item.video_versions?.[0]?.url || item.video_url || '',
    caption: (item.caption?.text || '').slice(0, 500),
    likes: item.like_count || 0,
    views: item.play_count || item.view_count || 0,
    comments: item.comment_count || 0,
    taken_at: item.taken_at || 0
  }));
return reels.map(r => ({ json: r }));

