const reel = $('Loop Reels').item.json;
const transcriptData = $input.first().json;
const transcript = transcriptData.text || transcriptData.transcript || '';
return [{ json: { ...reel, transcript } }];

const reel = $('Merge Transcript').item.json;
const llmResponse = $input.first().json;

let analysis = {};
try {
  const content = llmResponse.choices?.[0]?.message?.content || '{}';
  analysis = JSON.parse(content);
} catch(e) {
  analysis = { hook: '', hook_type: 'Unknown', body_summary: '', cta: 'None', topic: '', format: 'Unknown', emotional_trigger: 'Unknown', funnel_stage: 'TOFU', steal_worthy: false, steal_reason: 'Parse failed' };
}

const str = v => Array.isArray(v) ? (v[0] || '') : (v || '');

return [{ json: {
  competitor: '@' + reel.username,
  threat_level: reel.threat,
  reel_url: reel.reel_url,
  scraped_date: new Date().toISOString().split('T')[0],
  caption: reel.caption || '',
  transcript: reel.transcript || '',
  likes: reel.likes || 0,
  views: reel.views || 0,
  comments: reel.comments || 0,
  hook: str(analysis.hook),
  hook_type: str(analysis.hook_type) || 'Unknown',
  body_summary: str(analysis.body_summary),
  cta: str(analysis.cta) || 'None',
  topic: str(analysis.topic),
  format: str(analysis.format) || 'Unknown',
  emotional_trigger: str(analysis.emotional_trigger) || 'Unknown',
  funnel_stage: str(analysis.funnel_stage) || 'TOFU',
  steal_worthy: analysis.steal_worthy === true,
  steal_reason: str(analysis.steal_reason)
} }];

// Collect all reel URLs already in Notion
const existingItems = $('Get Existing Reels').all();
const existingUrls = new Set(
  existingItems
    .map(item => {
      const props = item.json.properties || {};
      const reelUrlProp = props['Reel URL'];
      return reelUrlProp?.url || '';
    })
    .filter(Boolean)
);

// Get scraped reels from Merge All Reels
const allReels = $('Merge All Reels').all();

// Filter out duplicates
const newReels = allReels.filter(item => {
  const url = item.json.reel_url || '';
  return url && !existingUrls.has(url);
});

if (newReels.length === 0) {
  throw new Error('No new reels to process — all already in Notion');
}

return newReels;

